'use client'

import {
  Bar,
  BarChart,
  CartesianGrid,
  ResponsiveContainer,
  Tooltip,
  XAxis,
  YAxis,
} from 'recharts'

interface Metric {
  metricName: string
  value: number
}

export default function MetricsChart({ metrics }: { metrics?: Metric[] }) {
  const data =
    metrics?.map((metric) => ({
      name: metric.metricName.replaceAll('_', ' '),
      value: Number(metric.value.toFixed(2)),
    })) ?? []

  if (!data.length) return null

  return (
    <div className="h-[320px] rounded-2xl border border-zinc-800 bg-zinc-900/70 p-4">
      <ResponsiveContainer width="100%" height="100%">
        <BarChart data={data}>
          <CartesianGrid stroke="#27272a" strokeDasharray="3 3" />
          <XAxis dataKey="name" stroke="#a1a1aa" tickLine={false} axisLine={false} />
          <YAxis stroke="#a1a1aa" tickLine={false} axisLine={false} />
          <Tooltip
            contentStyle={{
              backgroundColor: '#09090b',
              border: '1px solid #27272a',
              borderRadius: '12px',
              color: '#fafafa',
            }}
          />
          <Bar dataKey="value" fill="#fafafa" radius={[8, 8, 0, 0]} />
        </BarChart>
      </ResponsiveContainer>
    </div>
  )
}
